function deepClone(value) {
  return JSON.parse(JSON.stringify(value));
}

export function getEmbeddedPresetIds() {
  return Object.keys(EMBEDDED_PRESETS)
    .map(value => Number.parseInt(value, 10))
    .filter(Number.isFinite)
    .sort((a, b) => a - b);
}

export function getEmbeddedPresetById(presetId) {
  const key = Number.parseInt(`${presetId}`, 10);
  if (!Number.isFinite(key) || !Object.hasOwn(EMBEDDED_PRESETS, key)) {
    return null;
  }

  return deepClone(EMBEDDED_PRESETS[key]);
}

export function registerEmbeddedPreset(presetId, preset) {
  const key = Number.parseInt(`${presetId}`, 10);
  if (!Number.isFinite(key) || key < 0 || !preset || typeof preset !== 'object') {
    return false;
  }

  EMBEDDED_PRESETS[key] = deepClone(preset);
  return true;
}

export { EMBEDDED_PRESETS };
